4	describe("Game of Life", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep still life block unchanged", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	  });
17	  it("should kill live cell with more than 3 neighbors (overpopulation)", () => {
18	    // Center (5,5) with 4 diagonal neighbors: each corner sees only center (1 neighbor -> underpop)
19	    // Center has 4 neighbors -> dies (overpopulation); corners have 1 neighbor -> die (underpopulation)
20	    // Mid-edge dead cells (4,5),(5,4),(5,6),(6,5) each have exactly 3 live neighbors -> born
21	    expect(nextGeneration([[5, 5], [4, 4], [6, 4], [4, 6], [6, 6]])).toEqual([[4, 5], [5, 4], [5, 6], [6, 5]]);
22	  });
23	  it("should revive dead cell with exactly 3 live neighbors (reproduction)", () => {
24	    // L-shape: (0,0),(1,0),(0,1) — dead cell (1,1) has exactly 3 live neighbors → becomes alive
25	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
26	  });
27	  it("should transform blinker from vertical to horizontal", () => {
28	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
29	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
30	    const result = nextGeneration(vertical);
31	    expect(result).toHaveLength(horizontal.length);
