1	const containsCell = (grid: [number, number][], [x, y]: [number, number]): boolean =>
2	  grid.some(([cx, cy]) => cx === x && cy === y);
3	
4	const countNeighbors = (cell: [number, number], cells: [number, number][]): number => {
5	  const [x, y] = cell;
6	  return cells.filter(([cx, cy]) =>
7	    !(cx === x && cy === y) &&
8	    Math.abs(cx - x) <= 1 &&
9	    Math.abs(cy - y) <= 1
10	  ).length;
11	};
12	
13	export function nextGeneration(cells: [number, number][]): [number, number][] {
14	  const survivors = cells.filter(cell => {
15	    const neighborCount = countNeighbors(cell, cells);
16	    return neighborCount === 2 || neighborCount === 3;
17	  });
18	
19	  const adjacentDeadCells: [number, number][] = [];
20	  for (const [x, y] of cells) {
21	    for (let dx = -1; dx <= 1; dx++) {
22	      for (let dy = -1; dy <= 1; dy++) {
23	        if (dx === 0 && dy === 0) continue;
24	        const nx = x + dx;
25	        const ny = y + dy;
26	        const isLive = containsCell(cells, [nx, ny]);
27	        const alreadyAdded = containsCell(adjacentDeadCells, [nx, ny]);
28	        if (!isLive && !alreadyAdded) {
29	          adjacentDeadCells.push([nx, ny]);
30	        }
31	      }
32	    }
33	  }
34	
35	  const born = adjacentDeadCells.filter(cell => countNeighbors(cell, cells) === 3);
36	
37	  return [...survivors, ...born];
38	}
